solution:
function deepClone<T>(obj: T): T {
  const map = new WeakMap();

  function clone(value: any): any {
    // Handle primitives and null
    if (value === null || typeof value !== 'object') {
      return value;
    }

    // Handle circular references
    if (map.has(value)) {
      return map.get(value);
    }

    // Handle Date
    if (value instanceof Date) {
      return new Date(value.getTime());
    }

    // Handle RegExp
    if (value instanceof RegExp) {
      return new RegExp(value.source, value.flags);
    }

    // Handle Map
    if (value instanceof Map) {
      const clonedMap = new Map();
      map.set(value, clonedMap);
      value.forEach((v, k) => {
        clonedMap.set(clone(k), clone(v));
      });
      return clonedMap;
    }

    // Handle Set
    if (value instanceof Set) {
      const clonedSet = new Set();
      map.set(value, clonedSet);
      value.forEach((v) => {
        clonedSet.add(clone(v));
      });
      return clonedSet;
    }

    // Handle Array
    if (Array.isArray(value)) {
      const clonedArray: any[] = [];
      map.set(value, clonedArray);
      value.forEach((item, index) => {
        clonedArray[index] = clone(item);
      });
      return clonedArray;
    }

    // Handle Object
    const clonedObj: any = {};
    map.set(value, clonedObj);
    for (const key in value) {
      if (value.hasOwnProperty(key)) {
        clonedObj[key] = clone(value[key]);
      }
    }
    return clonedObj;
  }

  return clone(obj);
}

