function curry<T extends (...args: any[]) => any>(
  func: T,
  arity?: number
): (...args: any[]) => any {
  const _arity = arity ?? func.length;

  return function curried(...args: any[]): any {
    if (args.length >= _arity) {
      return func.apply(this, args);
    }

    return (...nextArgs: any[]) => {
      return curried.apply(this, args.concat(nextArgs));
    };
  };
}

