  private usePriority: boolean = false;
  private resolveQueue: (() => void)[] = [];

  constructor(options: AsyncQueueOptions) {
    this.concurrency = Math.max(1, options.concurrency);
    this.usePriority = options.priority ?? false;
  }

  enqueue(task: () => Promise<any>, priority: number = 0): void {
    const index = this.taskIndex++;
    this.queue.push({ fn: task, priority, index });
    if (this.usePriority) {
      this.queue.sort((a, b) => b.priority - a.priority);
    }
  }

  async start(): Promise<any[]> {
    const promises: Promise<void>[] = [];
    for (let i = 0; i < this.concurrency; i++) {
      promises.push(this.process());
    }
    await Promise.all(promises);
    return Array.from({ length: this.taskIndex }, (_, i) => this.results.get(i));
  }

  pause(): void {
    this.paused = true;
  }

  resume(): void {
    this.paused = false;
    this.resolveQueue.forEach(resolve => resolve());
    this.resolveQueue = [];
  }

  private async waitIfPaused(): Promise<void> {
    while (this.paused) {
      await new Promise(resolve => this.resolveQueue.push(resolve));
    }
  }

  private async process(): Promise<void> {
    while (this.queue.length > 0) {
      await this.waitIfPaused();
      if (this.queue.length === 0) break;

      const task = this.queue.shift();
      if (!task) break;

      this.running++;
      try {
        const result = await task.fn();
        this.results.set(task.index, result);
      } catch (error) {
        this.errors.push(error instanceof Error ? error : new Error(String(error)));
        this.results.set(task.index, undefined);
      }
      this.running--;
    }
  }
}

