class CancelledError extends Error {
  constructor(message: string = 'Promise was cancelled') {
    super(message);
    this.name = 'CancelledError';
  }
}

type CancellableExecutor<T> = (
  resolve: (value: T | PromiseLike<T>) => void,
  reject: (reason?: any) => void,
  signal: AbortSignal
) => void;

class CancellablePromise<T> extends Promise<T> {
  private abortController: AbortController;
  private timeoutId?: NodeJS.Timeout;
  private _cancelled: boolean = false;
  private settled: boolean = false;

  constructor(executor: CancellableExecutor<T>, timeout?: number) {
    let resolveRef: (value: T | PromiseLike<T>) => void;
    let rejectRef: (reason?: any) => void;

    super((resolve, reject) => {
      resolveRef = (value: T | PromiseLike<T>) => {
        if (!this._cancelled) {
          this.settled = true;
          resolve(value);
        }
      };

      rejectRef = (reason?: any) => {
        if (!this._cancelled) {
          this.settled = true;
          reject(reason);
        }
      };

      try {
        executor(resolveRef, rejectRef, this.abortController.signal);
      } catch (error) {
        rejectRef(error);
      }
    });

    this.abortController = new AbortController();

    if (timeout !== undefined && timeout > 0) {
      this.timeoutId = setTimeout(() => {
        if (!this.settled && !this._cancelled) {
          this.cancel();
        }
      }, timeout);
    }
  }

  cancel(): void {
    if (!this._cancelled && !this.settled) {
      this._cancelled = true;
      this.abortController.abort();
      this.cleanup();
    }
  }

  isCancelled(): boolean {
    return this._cancelled;
  }

  private cleanup(): void {
    if (this.timeoutId !== undefined) {
      clearTimeout(this.timeoutId);
      this.timeoutId = undefined;
    }
  }
}

// Export for use
export { CancellablePromise, CancelledError };

