      next: (value) => !unsubscribed && observer.next?.(value),
      error: (error) => !unsubscribed && observer.error?.(error),
      complete: () => !unsubscribed && observer.complete?.()
    };
    const unsubscribe = this.subscribeFn(safeObserver);
    return {
      unsubscribe: () => {
        unsubscribed = true;
        unsubscribe();
      }
    };
  }

  map<U>(fn: (value: T) => U): Observable<U> {
    return new Observable<U>((observer) => {
      return this.subscribe({
        next: (value) => observer.next?.(fn(value)),
        error: (error) => observer.error?.(error),
        complete: () => observer.complete?.()
      }).unsubscribe;
    });
  }

  filter(predicate: (value: T) => boolean): Observable<T> {
    return new Observable<T>((observer) => {
      return this.subscribe({
        next: (value) => predicate(value) && observer.next?.(value),
        error: (error) => observer.error?.(error),
        complete: () => observer.complete?.()
      }).unsubscribe;
    });
  }

  take(count: number): Observable<T> {
    return new Observable<T>((observer) => {
      let taken = 0;
      const subscription = this.subscribe({
        next: (value) => {
          if (taken < count) {
            observer.next?.(value);
            taken++;
            if (taken === count) {
              observer.complete?.();
              subscription.unsubscribe();
            }
          }
        },
        error: (error) => observer.error?.(error),
        complete: () => observer.complete?.()
      });
      return () => subscription.unsubscribe();
    });
  }

  catchError(handler: (error: Error) => Observable<T>): Observable<T> {
    return new Observable<T>((observer) => {
      const subscription = this.subscribe({
        next: (value) => observer.next?.(value),
        error: (error) => {
          const recovery = handler(error);
          return recovery.subscribe(observer).unsubscribe;
        },
        complete: () => observer.complete?.()
      });
      return () => subscription.unsubscribe();
    });
  }
}

description.en:
Implement a CancellablePromise class that wraps standard promises and allows cancellation with proper cleanup. Requirements:

- Support promise-like behavior (.then, .catch, .finally)
- Allow external cancellation via cancel() method
- Automatic cancellation on timeout
- Reject with specific CancelledError on cancellation
- Cleanup callbacks for resource management
- Propagate cancellation through promise chains

**Signature:**
typescript
class CancellablePromise<T> implements PromiseLike<T> {
  constructor(executor: (resolve: (value: T) => void, reject: (reason?: any) => void, onCancel: (callback: () => void) => void) => void);
  then<U>(onFulfilled?: (value: T) => U | PromiseLike<U>, onRejected?: (reason: any) => U | PromiseLike<U>): CancellablePromise<U>;
  catch<U>(onRejected?: (reason: any) => U | PromiseLike<U>): CancellablePromise<U>;
  finally(onFinally?: () => void | PromiseLike<void>): CancellablePromise<T>;
  cancel(): void;
  timeout(ms: number): CancellablePromise<T>;
}

class CancelledError extends Error {
  constructor(message?: string);
}


**Example:**

const promise = new CancellablePromise<string>((resolve, reject, onCancel) => {
  const timeout = setTimeout(() => resolve('done'), 5000);
  onCancel(() => clearTimeout(timeout));
}).timeout(1000);

let error: Error | null = null;
promise.catch(e => { error = e; });

await delay(1100);
console.log(error instanceof CancelledError); // true
console.log(error.message); // 'Promise timeout after 1000ms'


**Edge cases:**
- Cancel after already resolved should be no-op
- Cleanup callbacks must always be called
- Timeout should not fire if resolved before timeout
- Chained promises should inherit cancellation capability

