class CancelledError extends Error {
  constructor(message: string = 'Promise was cancelled') {
    super(message);
    this.name = 'CancelledError';
  }
}

class CancellablePromise<T> implements PromiseLike<T> {
  private settled: boolean = false;
  private cleanupCallbacks: Array<() => void> = [];
  private internalPromise: Promise<T>;
  private internalResolve!: (value: T) => void;
  private internalReject!: (reason?: any) => void;

  constructor(
    executor: (
      resolve: (value: T) => void,
      reject: (reason?: any) => void,
      onCancel: (callback: () => void) => void
    ) => void
  ) {
    this.internalPromise = new Promise<T>((resolve, reject) => {
      this.internalResolve = (value) => {
        if (!this.settled) {
          this.settled = true;
          resolve(value);
        }
      };
      this.internalReject = (reason) => {
        if (!this.settled) {
          this.settled = true;
          reject(reason);
        }
      };
      executor(this.internalResolve, this.internalReject, (cb) => this.cleanupCallbacks.push(cb));
    });
  }

  then<U>(onFulfilled?: (value: T) => U | PromiseLike<U>, onRejected?: (reason: any) => U | PromiseLike<U>): CancellablePromise<U> {
    return new CancellablePromise<U>((resolve, reject, onCancel) => {
      this.internalPromise.then(
        (value) => {
          try {
            const result = onFulfilled?.(value);
            resolve(result instanceof CancellablePromise ? result as any : result as U);
          } catch (error) {
            reject(error);
          }
        },
        (reason) => {
          try {
            const result = onRejected?.(reason);
            resolve(result instanceof CancellablePromise ? result as any : result as U);
          } catch (error) {
            reject(error);
          }
        }
      );
      onCancel(() => this.cancel());
    });
  }

  catch<U>(onRejected?: (reason: any) => U | PromiseLike<U>): CancellablePromise<U> {
    return new CancellablePromise<U>((resolve, reject, onCancel) => {
      this.internalPromise.catch((reason) => {
        try {
          const result = onRejected?.(reason);
          resolve(result instanceof CancellablePromise ? result as any : result as U);
        } catch (error) {
          reject(error);
        }
      });
      onCancel(() => this.cancel());
    });
  }

  finally(onFinally?: () => void | PromiseLike<void>): CancellablePromise<T> {
    return new CancellablePromise<T>((resolve, reject, onCancel) => {
      this.internalPromise.finally(() => {
        try {
          return onFinally?.();
        } catch (error) {
          reject(error);
          return;
        }
      }).then(resolve, reject);
      onCancel(() => this.cancel());
    });
  }

  cancel(): void {
    if (!this.settled) {
      this.executeCleanup();
      this.internalReject(new CancelledError('Promise was cancelled'));
    }
  }

  timeout(ms: number): CancellablePromise<T> {
    return new CancellablePromise<T>((resolve, reject, onCancel) => {
      const timeoutId = setTimeout(() => {
        if (!this.settled) {
          this.cancel();
          reject(new CancelledError(`Promise timeout after ${ms}ms`));
        }
      }, ms);
      onCancel(() => clearTimeout(timeoutId));
      this.then(resolve, reject);
    });
  }

  private executeCleanup(): void {
    this.cleanupCallbacks.forEach((cb) => {
      try {
        cb();
      } catch (error) {
        console.error('Cleanup callback error:', error);
      }
    });
  }

  [Symbol.toStringTag] = 'CancellablePromise';
}
